const express = require('express');
const { createServer } = require('http');
const { Server } = require('socket.io');

const app = express();
const httpServer = createServer(app);

// Strict Origin validation with allowlist
const ALLOWED_ORIGINS = [
  'https://app.example.com',
  'https://admin.example.com',
  /^https:\/\/.*\.example\.com$/  // Allow all example.com subdomains
];

const io = new Server(httpServer, {
  cors: {
    origin: (origin, callback) => {
      // Allow requests with no origin (mobile apps, curl, etc.)
      if (!origin) {
        return callback(new Error('Origin header required'));
      }

      // Check if origin matches allowlist
      const isAllowed = ALLOWED_ORIGINS.some(allowedOrigin => {
        if (typeof allowedOrigin === 'string') {
          return origin === allowedOrigin;
        }
        if (allowedOrigin instanceof RegExp) {
          return allowedOrigin.test(origin);
        }
        return false;
      });

      if (isAllowed) {
        callback(null, true);
      } else {
        console.warn(`Rejected WebSocket connection from unauthorized origin: ${origin}`);
        callback(new Error('Origin not allowed'));
      }
    },
    credentials: true,
    methods: ['GET', 'POST']
  }
});

// Additional handshake authentication with CSRF token
io.use((socket, next) => {
  const token = socket.handshake.auth.token;
  const csrfToken = socket.handshake.headers['x-csrf-token'];

  if (!token || !csrfToken) {
    return next(new Error('Authentication required'));
  }

  // Validate JWT and CSRF token
  try {
    const decoded = verifyJWT(token);
    if (!validateCSRFToken(csrfToken, decoded.userId)) {
      return next(new Error('Invalid CSRF token'));
    }
    socket.userId = decoded.userId;
    next();
  } catch (err) {
    next(new Error('Invalid authentication'));
  }
});

io.on('connection', (socket) => {
  console.log(`User ${socket.userId} connected from ${socket.handshake.headers.origin}`);

  socket.on('message', (data) => {
    // Handle messages with validated origin and authentication
    console.log(`Message from user ${socket.userId}:`, data);
  });
});

httpServer.listen(3000, () => {
  console.log('Server listening on port 3000');
});

import org.springframework.context.annotation.Configuration;
import org.springframework.messaging.Message;
import org.springframework.messaging.MessageChannel;
import org.springframework.messaging.simp.config.ChannelRegistration;
import org.springframework.messaging.simp.config.MessageBrokerRegistry;
import org.springframework.messaging.simp.stomp.StompCommand;
import org.springframework.messaging.simp.stomp.StompHeaderAccessor;
import org.springframework.messaging.support.ChannelInterceptor;
import org.springframework.messaging.support.MessageHeaderAccessor;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.web.socket.config.annotation.*;

import java.util.List;
import java.util.Set;

@Configuration
@EnableWebSocketMessageBroker
public class WebSocketConfig implements WebSocketMessageBrokerConfigurer {

    private static final Set<String> ALLOWED_ORIGINS = Set.of(
        "https://app.example.com",
        "https://admin.example.com"
    );

    @Override
    public void configureMessageBroker(MessageBrokerRegistry config) {
        config.enableSimpleBroker("/topic", "/queue");
        config.setApplicationDestinationPrefixes("/app");
    }

    @Override
    public void registerStompEndpoints(StompEndpointRegistry registry) {
        registry.addEndpoint("/ws")
            .setAllowedOriginPatterns(ALLOWED_ORIGINS.toArray(new String[0]))
            .withSockJS();
    }

    @Override
    public void configureClientInboundChannel(ChannelRegistration registration) {
        registration.interceptors(new ChannelInterceptor() {
            @Override
            public Message<?> preSend(Message<?> message, MessageChannel channel) {
                StompHeaderAccessor accessor = MessageHeaderAccessor.getAccessor(
                    message, StompHeaderAccessor.class
                );

                if (StompCommand.CONNECT.equals(accessor.getCommand())) {
                    // Validate Origin header
                    String origin = accessor.getFirstNativeHeader("origin");
                    if (origin == null || !ALLOWED_ORIGINS.contains(origin)) {
                        throw new SecurityException("Unauthorized origin: " + origin);
                    }

                    // Extract and validate JWT token from header
                    String authToken = accessor.getFirstNativeHeader("Authorization");
                    if (authToken == null || !authToken.startsWith("Bearer ")) {
                        throw new SecurityException("Missing or invalid authentication token");
                    }

                    String token = authToken.substring(7);
                    try {
                        // Validate JWT and extract user details
                        Claims claims = Jwts.parserBuilder()
                            .setSigningKey(getSigningKey())
                            .build()
                            .parseClaimsJws(token)
                            .getBody();

                        String username = claims.getSubject();
                        List<String> roles = claims.get("roles", List.class);

                        // Create authentication object
                        UsernamePasswordAuthenticationToken authentication = 
                            new UsernamePasswordAuthenticationToken(
                                username, null, getAuthorities(roles)
                            );

                        // Set authentication in accessor
                        accessor.setUser(authentication);
                        SecurityContextHolder.getContext().setAuthentication(authentication);

                    } catch (Exception e) {
                        throw new SecurityException("Invalid authentication token", e);
                    }
                }
                return message;
            }
        });
    }

    private Key getSigningKey() {
        // Retrieve signing key from secure vault (Azure Key Vault, AWS Secrets Manager)
        return Keys.hmacShaKeyFor(getJwtSecret().getBytes());
    }
}

const express = require('express');
const { createServer } = require('http');
const { Server } = require('socket.io');
const csrf = require('csurf');
const cookieParser = require('cookie-parser');
const session = require('express-session');
const crypto = require('crypto');

const app = express();
const httpServer = createServer(app);

// Session configuration
app.use(cookieParser());
app.use(session({
  secret: process.env.SESSION_SECRET,
  resave: false,
  saveUninitialized: false,
  cookie: {
    secure: true,
    httpOnly: true,
    sameSite: 'strict',
    maxAge: 3600000
  }
}));

// CSRF protection for HTTP routes
const csrfProtection = csrf({ cookie: false });

// Store CSRF tokens per session
const csrfTokenStore = new Map();

// Generate CSRF token for WebSocket connections
app.get('/api/ws-token', csrfProtection, (req, res) => {
  const wsToken = crypto.randomBytes(32).toString('hex');
  const userId = req.session.userId;

  if (!userId) {
    return res.status(401).json({ error: 'Not authenticated' });
  }

  // Store token with expiration
  csrfTokenStore.set(userId, {
    token: wsToken,
    expires: Date.now() + 300000 // 5 minutes
  });

  res.json({
    wsToken: wsToken,
    csrfToken: req.csrfToken()
  });
});

const ALLOWED_ORIGINS = [
  'https://app.example.com',
  'https://admin.example.com'
];

const io = new Server(httpServer, {
  cors: {
    origin: ALLOWED_ORIGINS,
    credentials: true
  }
});

// WebSocket authentication middleware with CSRF validation
io.use((socket, next) => {
  const origin = socket.handshake.headers.origin;
  const wsToken = socket.handshake.auth.wsToken;
  const userId = socket.handshake.auth.userId;

  // Validate Origin
  if (!origin || !ALLOWED_ORIGINS.includes(origin)) {
    console.warn(`[SECURITY] Rejected WS from unauthorized origin: ${origin}`);
    return next(new Error('Unauthorized origin'));
  }

  // Validate CSRF token
  if (!wsToken || !userId) {
    console.warn('[SECURITY] Missing WebSocket CSRF token or user ID');
    return next(new Error('CSRF token required'));
  }

  const storedToken = csrfTokenStore.get(userId);

  if (!storedToken) {
    console.warn(`[SECURITY] No CSRF token found for user ${userId}`);
    return next(new Error('Invalid CSRF token'));
  }

  // Check token expiration
  if (storedToken.expires < Date.now()) {
    console.warn(`[SECURITY] Expired CSRF token for user ${userId}`);
    csrfTokenStore.delete(userId);
    return next(new Error('CSRF token expired'));
  }

  // Validate token match
  if (storedToken.token !== wsToken) {
    console.warn(`[SECURITY] CSRF token mismatch for user ${userId}`);
    return next(new Error('Invalid CSRF token'));
  }

  // Token valid - remove it (single use)
  csrfTokenStore.delete(userId);

  // Set user context
  socket.userId = userId;
  console.log(`[INFO] User ${userId} authenticated via WebSocket with CSRF validation`);
  next();
});

io.on('connection', (socket) => {
  console.log(`WebSocket connection established for user ${socket.userId}`);

  socket.on('message', (data) => {
    console.log(`Message from user ${socket.userId}:`, data);
    socket.emit('response', { status: 'received', data });
  });

  socket.on('disconnect', () => {
    console.log(`User ${socket.userId} disconnected`);
  });
});

// Cleanup expired tokens every minute
setInterval(() => {
  const now = Date.now();
  for (const [userId, tokenData] of csrfTokenStore.entries()) {
    if (tokenData.expires < now) {
      csrfTokenStore.delete(userId);
    }
  }
}, 60000);

httpServer.listen(3000, () => {
  console.log('Server listening on port 3000 with CSRF protection');
});

